console.log('Executing swap transaction:', {
  provider: unifiedQuote.provider,
  to: txData.to,
  value: txData.value,
  chainId: txData.chainId,
  connectedChainId,
})

// Check if we need to switch chains
if (connectedChainId !== txData.chainId) {
  console.log('Switching chain from', connectedChainId, 'to', txData.chainId)
  try {
    await switchChain({ chainId: txData.chainId })
    toast.success('Chain switched successfully')
    await new Promise(resolve => setTimeout(resolve, 500))
  } catch (switchError) {
    console.error('Failed to switch chain:', switchError)
    toast.error('Please switch to the correct network in your wallet')
    setIsSwapping(false)
    return
  }
}

sendTransaction({
  to: txData.to as `0x${string}`,
  data: txData.data as `0x${string}`,
  value: BigInt(txData.value),
  chainId: txData.chainId,
}, {
  onSuccess: async (hash) => {
    console.log('Transaction submitted successfully:', hash)
    toast.success(`Swap submitted via ${unifiedQuote.provider.toUpperCase()}`)

    // For Relay swaps, index the transaction
    if (unifiedQuote.provider === 'relay') {
      try {
        console.log('Indexing transaction with Relay:', hash)
        await relayAPI.indexSingleTransaction({
          txHash: hash,
          chainId: txData.chainId,
        })
        console.log('Transaction indexed successfully')
      } catch (indexError) {
        console.error('Failed to index transaction:', indexError)
      }
    }

    // Monitor status based on provider
    // For now, just mark as complete after a delay
    setTimeout(() => {
      setIsSwapping(false)
      toast.success('Swap completed!')
      setFromAmount('')
      setToAmount('')
      loadSwapHistory()
      updateUserStreak()
    }, 3000)
  },
  onError: (error) => {
    console.error('Transaction failed:', error)
    const errorMessage = error instanceof Error ? error.message : 'Transaction failed'
    toast.error(errorMessage)
    setIsSwapping(false)
  }
})

